     1→<!DOCTYPE html>
     2→<html lang="ko">
     3→<head>
     4→  <meta charset="UTF-8">
     5→  <meta name="viewport" content="width=device-width, initial-scale=1.0">
     6→  <title>AI 통합 모니터링 — 전체 아키텍처 (기존 + 고도화)</title>
     7→  <style>
     8→    * { box-sizing: border-box; margin: 0; padding: 0; }
     9→
    10→    body {
    11→      font-family: 'Segoe UI', 'Apple SD Gothic Neo', sans-serif;
    12→      background: #0d1117;
    13→      color: #e6edf3;
    14→      padding: 28px 32px;
    15→      min-width: 1440px;
    16→    }
    17→
    18→    /* ── 헤더 ── */
    19→    .page-header { text-align: center; margin-bottom: 10px; }
    20→    .page-header h1 { font-size: 19px; font-weight: 700; color: #f0f6fc; margin-bottom: 5px; }
    21→    .page-header p  { font-size: 12px; color: #7d8590; }
    22→
    23→    /* ── 범례 ── */
    24→    .legend {
    25→      display: flex; gap: 20px; justify-content: center;
    26→      margin-bottom: 22px; flex-wrap: wrap;
    27→    }
    28→    .legend-item { display: flex; align-items: center; gap: 6px; font-size: 12px; color: #8b949e; }
    29→    .legend-dot  { width: 12px; height: 12px; border-radius: 3px; flex-shrink: 0; }
    30→    .dot-existing { background: #b45309; border: 1px solid #f97316; }
    31→    .dot-new      { background: #1a3424; border: 1px solid #3fb950; }
    32→    .dot-internet { background: #0c1929; border: 2px solid #3b82f6; }
    33→    .dot-intranet { background: #1a1200; border: 2px solid #d29922; }
    34→    .dot-backup   { background: #12100e; border: 1.5px solid #6b7280; }
    35→    .dot-rpm      { background: #374151; border: 1px dashed #9ca3af; }
    36→    .dot-docker   { background: #081e22; border: 1px solid #06b6d4; }
    37→    .dot-jar      { background: #1f1005; border: 1px solid #fb923c; }
    38→
    39→    /* ── 최상위 ── */
    40→    .main-wrap {
    41→      display: flex; flex-direction: column;
    42→      align-items: center; gap: 0;
    43→    }
    44→
    45→    /* ── 공용 섹션 테두리 ── */
    46→    .section {
    47→      width: 100%; max-width: 1380px;
    48→      border-radius: 12px; padding: 16px 18px;
    49→    }
    50→    .sec-label {
    51→      font-size: 10px; font-weight: 700; letter-spacing: 1.1px;
    52→      text-transform: uppercase; margin-bottom: 12px; opacity: 0.8;
    53→    }
    54→
    55→    /* ── HQ ── */
    56→    .sec-hq { background: #161b22; border: 1.5px solid #1f4068; }
    57→    .sec-hq .sec-label { color: #58a6ff; }
    58→    .hq-inner { display: flex; gap: 14px; }
    59→    .hq-git {
    60→      flex: 1; background: #0d1117; border: 1px solid #1f4068;
    61→      border-radius: 8px; padding: 12px 14px;
    62→    }
    63→    .hq-git h3 { font-size: 12px; font-weight: 600; color: #58a6ff; margin-bottom: 8px; }
    64→    .mono { font-size: 11px; font-family: monospace; color: #8b949e; line-height: 1.9; }
    65→    .mono .hl { color: #e3b341; }
    66→    .hq-cards { display: flex; flex-direction: column; gap: 10px; min-width: 200px; }
    67→    .hq-card  {
    68→      background: #0d1117; border: 1px solid #30363d;
    69→      border-radius: 8px; padding: 10px 14px; flex: 1;
    70→    }
    71→    .hq-card h4 { font-size: 11px; font-weight: 600; color: #8b949e; margin-bottom: 4px; }
    72→    .hq-card p  { font-size: 11px; color: #6e7681; line-height: 1.5; }
    73→
    74→    /* ── 연결선 ── */
    75→    .vconn {
    76→      display: flex; flex-direction: column; align-items: center; padding: 3px 0;
    77→    }
    78→    .vline { width: 2px; height: 14px; background: #444c56; }
    79→    .vtag  {
    80→      font-size: 11px; color: #7d8590; background: #0d1117;
    81→      padding: 2px 14px; border-radius: 10px; border: 1px solid #30363d;
    82→      white-space: nowrap; margin: 2px 0;
    83→    }
    84→
    85→    /* ── 현장 섹션 ── */
    86→    .sec-site { background: #161b22; border: 1.5px solid #238636; }
    87→    .sec-site > .sec-label { color: #3fb950; }
    88→
    89→    /* ══════════════════════════════════════════
    90→       핵심: 3열 그리드 (모든 행 동일 컬럼 사용)
    91→       col1: 인터넷망  col2: 업무망  col3: 백업+우측
    92→    ══════════════════════════════════════════ */
    93→    .site-grid {
    94→      display: grid;
    95→      grid-template-columns: 1fr 1fr 1fr;
    96→      grid-template-rows: auto auto;
    97→      gap: 12px;
    98→    }
    99→
   100→    /* 상단 행 */
   101→    .cell-internet { grid-column: 1; grid-row: 1; }
   102→    .cell-intranet { grid-column: 2; grid-row: 1; }
   103→    .cell-backup   { grid-column: 3; grid-row: 1; }
   104→
   105→    /* 하단 행 */
   106→    .cell-mon      { grid-column: 1 / 3; grid-row: 2; } /* col1~2 span */
   107→    .cell-right    { grid-column: 3;     grid-row: 2; } /* col3 */
   108→
   109→    /* ── 망 박스 ── */
   110→    .net-box { border-radius: 10px; padding: 12px 14px; height: 100%; }
   111→    .net-internet { background: #0c1929; border: 1.5px solid #3b82f6; }
   112→    .net-intranet { background: #1a1200; border: 1.5px solid #d29922; }
   113→    .net-backup   { background: #12100e; border: 1.5px solid #6b7280; }
   114→    .net-label {
   115→      font-size: 10px; font-weight: 700; letter-spacing: 0.8px;
   116→      text-transform: uppercase; margin-bottom: 10px;
   117→    }
   118→    .net-internet .net-label { color: #3b82f6; }
   119→    .net-intranet .net-label { color: #d29922; }
   120→    .net-backup   .net-label { color: #9ca3af; }
   121→    .net-servers  { display: flex; gap: 10px; }
   122→
   123→    /* ── 개별 서버 ── */
   124→    .srv {
   125→      background: #0d1117; border: 1px solid #30363d;
   126→      border-radius: 8px; padding: 10px 12px; flex: 1;
   127→    }
   128→    .srv-name { font-size: 12px; font-weight: 700; color: #e6edf3; margin-bottom: 2px; }
   129→    .srv-ip   { font-size: 10px; font-family: monospace; color: #7d8590; margin-bottom: 8px; }
   130→    .srv-comps { display: flex; flex-direction: column; gap: 5px; }
   131→
   132→    .comp {
   133→      border-radius: 5px; padding: 5px 8px;
   134→      display: flex; align-items: center; gap: 5px; flex-wrap: wrap;
   135→    }
   136→    .comp-e { background: #2d1810; border: 1px solid #92400e; }
   137→    .comp-n { background: #0d1f12; border: 1px solid #166534; }
   138→    .comp-name { font-size: 11px; font-weight: 600; flex: 1; }
   139→    .comp-e .comp-name { color: #f97316; }
   140→    .comp-n .comp-name { color: #4ade80; }
   141→    .comp-port { font-size: 10px; font-family: monospace; color: #6e7681; }
   142→
   143→    /* 태그 */
   144→    .tag {
   145→      font-size: 9px; padding: 1px 5px; border-radius: 3px; font-weight: 700;
   146→      white-space: nowrap; flex-shrink: 0;
   147→    }
   148→    .tag-new    { background: #166534; color: #4ade80; }
   149→    .tag-rpm    { background: #374151; color: #9ca3af; }
   150→    .tag-docker { background: #081e22; color: #22d3ee; }
   151→    .tag-jar    { background: #1f1005; color: #fb923c; }
   152→
   153→    /* ── 모니터링 서버 (col1-2) ── */
   154→    .mon-box {
   155→      background: #0c1929; border: 2px solid #3b82f6;
   156→      border-radius: 10px; padding: 14px 16px; height: 100%;
   157→    }
   158→    .mon-title {
   159→      font-size: 13px; font-weight: 700; color: #e6edf3; margin-bottom: 2px;
   160→    }
   161→    .mon-ip { font-size: 11px; font-family: monospace; color: #7d8590; margin-bottom: 12px; }
   162→    .mon-inner { display: grid; grid-template-columns: 1fr 1.5fr; gap: 10px; }
   163→
   164→    .mon-sub {
   165→      border-radius: 8px; padding: 10px 12px;
   166→    }
   167→    .mon-sub-e { background: #1a0e00; border: 1px solid #92400e; }
   168→    .mon-sub-n { background: #0d1f12; border: 1px solid #166534; }
   169→    .mon-sub-label {
   170→      font-size: 10px; font-weight: 700; letter-spacing: 0.8px;
   171→      text-transform: uppercase; margin-bottom: 8px;
   172→    }
   173→    .mon-sub-e .mon-sub-label { color: #f97316; }
   174→    .mon-sub-n .mon-sub-label { color: #4ade80; }
   175→    .mon-comps { display: flex; flex-direction: column; gap: 6px; }
   176→
   177→    .mc {
   178→      border-radius: 6px; padding: 7px 10px;
   179→      display: flex; align-items: center; gap: 8px;
   180→    }
   181→    .mc-e { background: #2d1810; border: 1px solid #92400e; }
   182→    .mc-n { background: #0d2a18; border: 1px solid #166534; }
   183→    .mc-name { font-size: 12px; font-weight: 700; }
   184→    .mc-e .mc-name { color: #f97316; }
   185→    .mc-n .mc-name { color: #4ade80; }
   186→    .mc-port { font-size: 11px; font-family: monospace; color: #7d8590; }
   187→    .mc-desc { font-size: 10px; color: #6e7681; margin-left: auto; }
   188→    .mc-tags { display: flex; gap: 4px; margin-left: auto; align-items: center; }
   189→
   190→    .mon-note {
   191→      margin-top: 8px; font-size: 10px; color: #6e7681;
   192→      font-style: italic; padding: 4px 2px;
   193→    }
   194→
   195→    /* ── 우측 열 (col3): RabbitMQ + 인프라 스택 ── */
   196→    .right-col { display: flex; flex-direction: column; gap: 10px; height: 100%; }
   197→
   198→    .rmq-box {
   199→      background: #1a0a04; border: 1px solid #92400e;
   200→      border-radius: 10px; padding: 12px 14px; flex: 1.5;
   201→    }
   202→    .rmq-title { font-size: 12px; font-weight: 700; color: #f97316; margin-bottom: 8px; }
   203→    .rmq-body  { font-size: 11px; font-family: monospace; color: #8b949e; line-height: 2; }
   204→    .rmq-body .ql { color: #fb923c; }
   205→    .rmq-ports { margin-top: 8px; }
   206→    .rmq-port  {
   207→      font-size: 10px; font-family: monospace; color: #6e7681;
   208→      display: flex; gap: 8px; margin-bottom: 3px;
   209→    }
   210→    .rmq-port .pn { color: #f87171; }
   211→
   212→    .infra-stack { display: flex; flex-direction: column; gap: 8px; flex: 1; }
   213→    .infra-item  {
   214→      background: #161b22; border: 1px solid #30363d;
   215→      border-radius: 8px; padding: 10px 12px; flex: 1;
   216→    }
   217→    .infra-item.new-item { border-color: #166534; background: #0d1f12; }
   218→    .infra-item h4 { font-size: 11px; font-weight: 600; color: #8b949e; margin-bottom: 4px; }
   219→    .infra-item.new-item h4 { color: #4ade80; }
   220→    .infra-item p  { font-size: 10px; color: #6e7681; line-height: 1.6; font-family: monospace; }
   221→
   222→    /* ── 배지 ── */
   223→    .badge { display: inline-block; font-size: 10px; padding: 1px 7px; border-radius: 20px; font-weight: 600; }
   224→    .b-green { background: #1a3424; color: #3fb950; }
   225→    .b-gray  { background: #21262d; color: #8b949e; }
   226→
   227→    /* ── 데이터 흐름 ── */
   228→    .flow-panel {
   229→      width: 100%; max-width: 1380px;
   230→      background: #161b22; border: 1px solid #30363d;
   231→      border-radius: 12px; padding: 16px 18px; margin-top: 14px;
   232→    }
   233→    .flow-title {
   234→      font-size: 10px; font-weight: 700; color: #7d8590;
   235→      letter-spacing: 1px; text-transform: uppercase; margin-bottom: 12px;
   236→    }
   237→    .flow-grid { display: grid; grid-template-columns: repeat(4,1fr); gap: 10px; }
   238→    .fi {
   239→      background: #0d1117; border-radius: 8px; padding: 10px 12px;
   240→      border-left: 3px solid;
   241→    }
   242→    .fi.fi-e { background: #1a0a04; border-left-color: #f97316; }
   243→    .fi.fi-n { background: #0d1f12; border-left-color: #3fb950; }
   244→    .fi-t { font-size: 11px; font-weight: 700; margin-bottom: 4px; }
   245→    .fi.fi-e .fi-t { color: #f97316; }
   246→    .fi.fi-n .fi-t { color: #3fb950; }
   247→    .fi-d { font-size: 10px; color: #6e7681; line-height: 1.7; font-family: monospace; }
   248→    .flow-group-label {
   249→      font-size: 10px; font-weight: 700; letter-spacing: 0.8px;
   250→      padding: 3px 10px; border-radius: 4px; display: inline-block; margin-bottom: 8px;
   251→    }
   252→    .flow-existing-label { color: #f97316; background: #1a0a04; }
   253→    .flow-new-label      { color: #3fb950; background: #0d1f12; margin-top: 12px; }
   254→
   255→    footer { text-align: center; font-size: 11px; color: #444c56; margin-top: 18px; }
   256→  </style>
   257→</head>
   258→<body>
   259→
   260→<div class="page-header">
   261→  <h1>AI Agent 기반 지능형 통합 모니터링 — 기존 인프라 + 고도화 설계</h1>
   262→  <p>실제 운영 아키텍처 기반 · 폐쇄망 다환경 배포 · GitOps · 2인팀 v1</p>
   263→</div>
   264→
   265→<div class="legend">
