   369→          <div class="net-label">🏢 업무망 (내부망)</div>
   370→          <div class="net-servers">
   371→            <div class="srv">
   372→              <div class="srv-name">new-safe-anl1</div>
   373→              <div class="srv-ip">10.177.18.138</div>
   374→              <div class="srv-comps">
   375→                <div class="comp comp-e">
   376→                  <span class="comp-name">LoadBalancer</span>
   377→                  <span class="comp-port">:8080 :8081</span>
   378→                  <span class="tag tag-jar">JAR</span>
   379→                </div>
   380→                <div class="comp comp-e">
   381→                  <span class="comp-name">Consumer1</span>
   382→                  <span class="comp-port">:8082 :8083</span>
